sys_script_include.script:
var IDPKubernetesConnector = Class.create();
IDPKubernetesConnector.prototype = {
    initialize: function() {
        this.baseUrl = gs.getProperty('x_12345.idp.k8s.api_url');
        this.token = gs.getProperty('x_12345.idp.k8s.api_token');
    },

    fetchData: function(entityId) {
        try {
            var url = this.baseUrl + '/api/v1/pods';
            if (entityId) {
                url += '/' + entityId;
            }

            var request = new sn_ws.RESTMessageV2();
            request.setEndpoint(url);
            request.setHttpMethod('GET');
            request.setRequestHeader('Authorization', 'Bearer ' + this.token);
            request.setRequestHeader('Content-Type', 'application/json');

            var response = request.execute();
            var responseBody = response.getBody();

            if (response.getStatusCode() == 200) {
                return JSON.parse(responseBody);
            }

            return null;
        } catch (ex) {
            gs.error('IDPKubernetesConnector.fetchData failed: ' + ex.getMessage());
            return null;
        }
    },

    type: 'IDPKubernetesConnector'
};
